mapper.select:
SELECT d.id, d.merchant_id, d.category_id, c.name AS category_name, d.name, d.price, d.image, d.description, d.status, d.create_time, d.update_time FROM dish d LEFT JOIN category c ON d.category_id = c.id WHERE d.merchant_id = #{query.merchantId}
AND d.name LIKE CONCAT('%', #{query.name}, '%')
AND d.category_id = #{query.categoryId}
AND d.status = #{query.status}
ORDER BY d.create_time DESC
